   167→impl LmFit {
   168→    /// Get the number of observations used in the model
   169→    pub fn n_obs(&self) -> usize {
   170→        self.n_obs
   171→    }
   172→
   173→    /// Get the rank of the design matrix (number of linearly independent columns)
   174→    pub fn rank(&self) -> usize {
   175→        self.rank
   176→    }
   177→
   178→    /// Get degrees of freedom for error (n_obs - rank)
   179→    pub fn df_resid(&self) -> usize {
   180→        self.n_obs.saturating_sub(self.rank)
   181→    }
   182→}
