   197→    fn summary(&self) -> ModelSummary {
   198→        use inference::{t_statistics, t_test_p_values};
   199→        
   200→        // Calculate residual standard error: s² = RSS / (n - p)
   201→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   202→        let df_resid = self.df_resid() as f64;
   203→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   204→        
   205→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   206→        // Compute X'X
   207→        let xtx = &self.x_matrix.transpose() * &self.x_matrix;
   208→        
   209→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability  
   210→        let qr = xtx.col_piv_qr();
   211→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   212→        let xtx_inv = qr.solve(&identity);
   213→        
   214→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   215→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   216→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   217→            .collect();
   218→        
   219→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   220→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   221→        
   222→        let mut coefficient_rows = Vec::new();
   223→        for (i, &coef) in self.coefficients.iter().enumerate() {
