/// Compute F-statistic p-value using F-distribution
/// 
/// For F(f; df1, df2) = P(F ≤ f), where F follows F-distribution with df1, df2 degrees of freedom
pub fn f_test_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
    if f_stat <= 0.0 || df1 <= 0 || df2 <= 0 {
        return 1.0;
    }

    // F distribution p-value: P(F > f_stat) = 1 - I_x(df1/2, df2/2)
    // where x = df1*f_stat / (df1*f_stat + df2) and I is regularized incomplete beta function
    let x = (df1 as f64 * f_stat) / (df1 as f64 * f_stat + df2 as f64);
    let a = df1 as f64 / 2.0;
    let b = df2 as f64 / 2.0;

    1.0 - incomplete_beta(a, b, x)
}

/// Calculate overall F-statistic for model significance
/// Tests null hypothesis that all non-intercept coefficients are zero
pub fn model_f_statistic(rss_full: f64, rss_null: f64, df_model: usize, df_resid: usize) -> f64 {
    if df_model == 0 || df_resid == 0 || rss_full <= 0.0 {
        return 0.0;
    }

    let explained_ss = rss_null - rss_full;
    let mse_model = explained_ss / df_model as f64;
    let mse_resid = rss_full / df_resid as f64;

    if mse_resid <= 0.0 {
        return f64::INFINITY;
    }

    mse_model / mse_resid
}

