    assert!(summary.f_statistic >= 0.0, "F-statistic should be non-negative");
    assert!(summary.f_p_value >= 0.0 && summary.f_p_value <= 1.0, "F p-value should be between 0 and 1");
    assert_eq!(summary.df_model, 1, "Model should have 1 degree of freedom (excluding intercept)");
    assert_eq!(summary.df_residual, 3, "Should have 3 residual degrees of freedom (5 obs - 2 params)");

    // With decent fit, R² should be reasonably high
    assert!(summary.r_squared > 0.8, "R² should be high for this near-linear relationship: {}", summary.r_squared);

    println!("Enhanced summary statistics:");
    println!("R² = {:.6}", summary.r_squared);
    println!("Adj R² = {:.6}", summary.adj_r_squared);
    println!("Residual SE = {:.6}", summary.residual_std_error);
    println!("F-statistic = {:.6}", summary.f_statistic);
    println!("F p-value = {:.6}", summary.f_p_value);
}

